import * as fromReachout from '../actions/reachout.actions';
import { ReachOutForm } from '../../models/reachoutform.model';

export interface ReachOutFormState {
    form: ReachOutForm;
    response: any;
    loaded: boolean;
    loading: boolean;
}

export const initialState: ReachOutFormState = {
    form: null,
    response: {},
    loaded: false,
    loading: false,
};

export function reducer(
    state = initialState,
    action: fromReachout.ReachOutFormActions
): ReachOutFormState {
    switch (action.type) {
        case fromReachout.REACHOUT_SUBMIT_FORM: {
            return {
                ...state,
                loading: true,
                form: action.payload,
            };
        }

        case fromReachout.REACHOUT_SUBMIT_FORM_SUCCESS: {

            return {
                ...state,
                loading: false,
                loaded: true,
                response: action.payload,
            };
        }

        case fromReachout.REACHOUT_SUBMIT_FORM_FAIL: {
            return {
                ...state,
                loading: false,
                loaded: false,
            };
        }
    }

    return state;
}

export const getReachOutData = (state: ReachOutFormState) => state.form;
export const getReachOutLoading = (state: ReachOutFormState) => state.loading;
export const getReachOutLoaded = (state: ReachOutFormState) => state.loaded;
