import { Component, OnInit, EventEmitter, Output, Input } from '@angular/core';
import { ThemeState, ToggleDarkMode } from 'src/app/app/store';
import { Store } from '@ngrx/store';

@Component({
  selector: 'rg-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent implements OnInit {

  @Input()
  public isDark: boolean;
  @Input()
  public isMenuOpen: boolean;

  @Output()
  public themeChanged = new EventEmitter<void>();
  @Output()
  public languageChanged = new EventEmitter<string>();
  @Output()
  public scrollToClicked = new EventEmitter<string>();
  @Output()
  public goToClicked = new EventEmitter<string>();
  @Output()
  public menuChanged = new EventEmitter<boolean>();
  @Output()
  public openedDialog = new EventEmitter<void>();

  constructor() { }

  ngOnInit() {
  }

  public toggleTheme(): void {
    this.themeChanged.emit();
  }

  public changeLanguage(newLanguage: string): void {
    this.languageChanged.emit(newLanguage);
  }

  public changeMenu(open: boolean): void {
    this.menuChanged.emit(open);
  }

  public goTo(elementId: string): void {
    this.menuChanged.emit(false);
    this.goToClicked.emit(elementId);
  }

  public openDialog(): void {
    this.openedDialog.emit();
  }

}
