import { Component, OnDestroy, Inject } from '@angular/core';
import { Subject, Observable } from 'rxjs';
import { map, takeUntil, filter } from 'rxjs/operators';
import { AppState, fromAppSelectors, ToggleDarkMode, OpenCloseMenu, Go } from 'src/app/app/store';
import { Store } from '@ngrx/store';
import { DOCUMENT } from '@angular/common';
import { MatDialog } from '@angular/material/dialog';
import { ReachOutDialogComponent } from '../../components';
import { PageScrollService } from 'ngx-page-scroll-core';

@Component({
  selector: 'rg-public',
  templateUrl: './public.component.html',
  styleUrls: ['./public.component.scss']
})
export class PublicComponent implements OnDestroy {

  public isDarkTheme: Observable<boolean>;
  public isMenuOpen: Observable<boolean>;

  private destroyed = new Subject<void>();
  private route$: Observable<string>;

  constructor(
    private appStore: Store<AppState>, private dialog: MatDialog,
    private pageScrollService: PageScrollService, @Inject(DOCUMENT) private document: any) {

    this.route$ = this.appStore.select(fromAppSelectors.fromRouter.getRouterState).pipe(map(routerState => routerState.state.url));
    this.isDarkTheme = this.appStore.select(fromAppSelectors.fromTheme.getDarkTheme);
    this.isMenuOpen = this.appStore.select(fromAppSelectors.fromTheme.getMenuOpen);
    this.route$.pipe(takeUntil(this.destroyed)).subscribe(route => this.scrollToClicked(route.substr(1)));
  }

  public ngOnDestroy(): void {
    this.destroyed.next();
    this.destroyed.complete();
  }

  public themeChanged() {
    this.appStore.dispatch(new ToggleDarkMode());
  }

  public languageChanged(newLanguage: string) {
    console.log(newLanguage);
  }

  public menuChanged(open: boolean) {
    this.appStore.dispatch(new OpenCloseMenu(open));
  }

  public scrollToClicked(elementId: string): void {
    const scrollTo = elementId !== '' ? elementId : 'home';
    this.pageScrollService.scroll({
      document: this.document,
      scrollTarget: '#' + scrollTo,
    });
  }

  public goTo(link: string) {
    this.appStore.dispatch(new Go({ path: [link] }));
  }

  public openDialog(): void {
    const dialogRef = this.dialog.open(ReachOutDialogComponent, {
      width: '500px',
      // data: {name: this.name, animal: this.animal}
    });
  }
}
