import { Component, OnInit, EventEmitter, Output } from '@angular/core';
import { ReachOutDialogComponent } from '../reach-out/reach-out.component';
import { MatDialog } from '@angular/material/dialog';
import { PublicState } from '../../store';
import { Store } from '@ngrx/store';
import { ReachOutFormState } from '../../store/reducers/reachout.reducers';
import { Observable } from 'rxjs';
import { getReachoutFormState } from '../../store/selectors/reachout.selectors';

@Component({
  selector: 'rg-projects',
  templateUrl: './projects.component.html',
  styleUrls: ['./projects.component.scss']
})
export class ProjectsComponent {

  @Output()
  public openedDialog = new EventEmitter<void>();

  public state: Observable<ReachOutFormState>;

  constructor(private store: Store<ReachOutFormState>) {
    this.state = this.store.select(getReachoutFormState);
  }

  public openDialog(): void {
    this.openedDialog.emit();
  }
}
