import { ActionReducerMap, createFeatureSelector, createSelector } from '@ngrx/store';

import * as fromReachOut from './reachout.reducers';

export interface PublicState {
  reachout: fromReachOut.ReachOutFormState;
}

export const reducers: ActionReducerMap<PublicState> = {
  reachout: fromReachOut.reducer,
};

export const getPublicState = createFeatureSelector<PublicState>(
  'public'
);


