import { Component, OnInit, ViewChild, ElementRef } from '@angular/core';
import Typewriter from 'typewriter-effect/dist/core';
import GraphemeSplitter from 'grapheme-splitter';


@Component({
  selector: 'rg-landing',
  templateUrl: './landing.component.html',
  styleUrls: ['./landing.component.scss']
})
export class LandingComponent implements OnInit {

  private tw;

  constructor() { }

  ngOnInit() {
    this.tw = new Typewriter('#typewriter', {
      loop: true,
      cursor: '',
      delay: 75,
      stringSplitter: (str: string) => {
        const splitter = new GraphemeSplitter();
        return splitter.splitGraphemes(str);
      }
    });

    this.buildTWForText('Hi I am Robin. ✋', '');
    this.buildTWForText('I am a software developer 💻', 'software');
    this.buildTWForText('And I love the mountains 🏔', 'mountains');
    this.buildTWForText('I work with Java and Angular ♨️', 'climb');
    this.buildTWForText('I just started climbing 🧗‍', 'climbing');
    this.buildTWForText('I also design and code websites for small businesses 🖥️', 'climbing');
    this.buildTWForText('In the winter I snowboard and ski 🎿', 'mountains');
    this.buildTWForText('For data I love to work with SQL 🗄️', 'climb');
    this.buildTWForText('I love all animals, but my heart belongs to dogs 🐕', 'mountains');
    this.buildTWForText('I am also a big fan of the cloud and have worked with Azure and AWS ☁️', 'climb');
    this.tw.start();
  }



  public buildTWForText(text: string, color: string) {
     this.tw
      .callFunction(() => {
      })
      .typeString(text)
      .callFunction(() => {
      })
      .pauseFor(600)
      .deleteAll();
  }
}
