import { Action } from '@ngrx/store';
import { ReachOutForm } from '../../models/reachoutform.model';

export const REACHOUT_SUBMIT_FORM = '[ReachOut] Submit Form';
export const REACHOUT_SUBMIT_FORM_SUCCESS = '[ReachOut] Submit Form Success';
export const REACHOUT_SUBMIT_FORM_FAIL = '[ReachOut] Submit Form Fail';

export class ReachoutSubmitForm implements Action {
    readonly type = REACHOUT_SUBMIT_FORM;
    constructor(public payload: ReachOutForm) { }
}

export class ReachoutSubmitFormSuccess implements Action {
    readonly type = REACHOUT_SUBMIT_FORM_SUCCESS;
    constructor(public payload: any) { }
}

export class ReachoutSubmitFormFail implements Action {
    readonly type = REACHOUT_SUBMIT_FORM_FAIL;
    constructor(public payload: any) { }
}

export type ReachOutFormActions = ReachoutSubmitForm | ReachoutSubmitFormSuccess | ReachoutSubmitFormFail;
