import { createSelector } from '@ngrx/store';

import { getReachOutLoaded, getReachOutLoading, getReachOutData } from '../reducers/reachout.reducers';
import { getPublicState, PublicState } from '../reducers';

export const getReachoutFormState = createSelector(
    getPublicState,
    (state: PublicState) => state.reachout
);

export const getData = createSelector(
    getReachoutFormState,
    getReachOutData
);

export const getLoaded = createSelector(
    getReachoutFormState,
    getReachOutLoaded
);

export const getLoading = createSelector(
    getReachoutFormState,
    getReachOutLoading
);

