import { Component, OnInit } from '@angular/core';
import { FormBuilder, Validators } from '@angular/forms';
import { ReachOutForm } from '../../models/reachoutform.model';
import { ReachOutFormState } from '../../store/reducers/reachout.reducers';
import { Store } from '@ngrx/store';
import { ReachoutSubmitForm } from '../../store/actions';
import { Observable } from 'rxjs';
import * as fromReachOutSelectors from '../../store/selectors/reachout.selectors';

@Component({
  selector: 'rg-reach-out',
  templateUrl: './reach-out.component.html',
  styleUrls: ['./reach-out.component.scss']
})
export class ReachOutDialogComponent {

  public loading: Observable<boolean>;
  public loaded: Observable<boolean>;

  public reachOutForm = this.fb.group({
    name: ['', Validators.required],
    email: ['', Validators.email],
    text: [''],
  });

  constructor(private fb: FormBuilder, private store: Store<ReachOutFormState>) {
    this.loading = this.store.select(fromReachOutSelectors.getLoading);
    this.loaded = this.store.select(fromReachOutSelectors.getLoaded);
  }

  public submit(): void {
    this.store.dispatch(new ReachoutSubmitForm(this.reachOutForm.value as ReachOutForm));
  }
}
