import { Injectable } from '@angular/core';
import { Effect, Actions, ofType } from '@ngrx/effects';
import { map, switchMap, catchError } from 'rxjs/operators';
import { of } from 'rxjs';
import { ReachoutService } from '../../services';

import * as reachOut from '../actions/reachout.actions';


@Injectable()
export class ReachOutEffects {
    constructor(
        private actions$: Actions,
        private reachoutService: ReachoutService,
    ) { }

    @Effect()
  submitForm$ = this.actions$.pipe(
    ofType(reachOut.REACHOUT_SUBMIT_FORM),
    switchMap(form => {
      return this.reachoutService
        .submitForm(form)
        .pipe(
          map(pizzas => new reachOut.ReachoutSubmitFormSuccess(pizzas)),
          catchError(error => of(new reachOut.ReachoutSubmitFormFail(error)))
        );
    })
  );

}
