import { Component, OnInit, ViewChild, AfterViewInit, ElementRef, ChangeDetectorRef } from '@angular/core';

@Component({
  selector: 'rg-work',
  templateUrl: './work.component.html',
  styleUrls: ['./work.component.scss']
})
export class WorkComponent implements AfterViewInit {

  @ViewChild('firstElement', {static: false}) firstElement: ElementRef;
  @ViewChild('wrapperElement', {static: false}) wrapperElement: ElementRef;

  private readonly OFFSET = 0;
  public closedHeight = 0;
  public openHeight = 1500;
  public hidden = true;

  constructor(private cdr: ChangeDetectorRef) { }

  ngAfterViewInit(): void {
    this.closedHeight = this.firstElement.nativeElement.offsetHeight + this.OFFSET;
    console.log(this.closedHeight);
    // this.openHeight = this.wrapperElement.nativeElement.offsetHeight + this.OFFSET;
    this.cdr.detectChanges();
  }

  public toggleWork(): void {
    this.hidden = !this.hidden;
  }
}
